import { readFileSync } from 'fs';
import * as XLSX from 'xlsx';
const buf = readFileSync('.swarm/ejemplo-emma.csv');
const ab = buf.buffer.slice(buf.byteOffset, buf.byteOffset + buf.byteLength);

// 1) parsearExcelSincronizacion (saltarEncabezado=false)
const wb = XLSX.read(ab, { type: 'array' });
const ws = wb.Sheets[wb.SheetNames[0]];
const rows = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });
console.log('Filas crudas leidas por xlsx:', rows.length);
console.log('Primera fila cruda:', JSON.stringify(rows[0]));
console.log('Ultima fila cruda:', JSON.stringify(rows[rows.length-1]));

// 2) parsearCSV preview (texto)
const texto = new TextDecoder().decode(ab);
const lineas = texto.replace(/\r\n/g,'\n').split('\n').filter(l=>l.trim()!=='');
console.log('Lineas de texto:', lineas.length);
console.log('Fila que parsearCSV usaria de encabezado:', JSON.stringify(lineas[0]));
"
